//! # C++ API Compatibility Layer\n//!\n//! This module provides a complete C++ compatible API that maintains the exact function\n//! signatures from the original MilesAudioDevice while using modern Rust implementations\n//! underneath. This ensures seamless integration with existing C++ code.\n\nuse super::{\n    MilesAudioDevice, MilesAudioConfig, AudioFormat, AudioFormatType, Priority, Volume,\n    Position3D, AudioListener, AudioSource, AudioHandle, DeviceManager, DeviceSelection,\n    Result as RustResult, AudioDeviceError,\n};\nuse std::sync::{Arc, Mutex, OnceLock};\nuse std::ffi::{CStr, CString, c_char, c_void};\nuse std::ptr;\nuse std::os::raw::{c_int, c_uint, c_float, c_double};\nuse tokio::runtime::Runtime;\n\n/// C-compatible result codes matching original C++ enum\n#[repr(C)]\n#[derive(Debug, Clone, Copy, PartialEq, Eq)]\npub enum CResult {\n    /// Operation successful\n    Success = 0,\n    /// Generic failure\n    Failure = -1,\n    /// Device initialization failed\n    InitFailed = -2,\n    /// Device not found\n    DeviceNotFound = -3,\n    /// Invalid parameter\n    InvalidParam = -4,\n    /// Device busy\n    DeviceBusy = -5,\n    /// Out of memory\n    OutOfMemory = -6,\n    /// Format not supported\n    FormatNotSupported = -7,\n    /// Hardware error\n    HardwareError = -8,\n}\n\n/// C-compatible audio format structure\n#[repr(C)]\n#[derive(Debug, Clone, Copy)]\npub struct CAudioFormat {\n    pub sample_rate: c_uint,\n    pub channels: c_uint,\n    pub bits_per_sample: c_uint,\n    pub format_type: c_int,\n}\n\n/// C-compatible position structure\n#[repr(C)]\n#[derive(Debug, Clone, Copy, Default)]\npub struct CPosition3D {\n    pub x: c_float,\n    pub y: c_float,\n    pub z: c_float,\n}\n\n/// C-compatible listener structure\n#[repr(C)]\n#[derive(Debug, Clone, Copy)]\npub struct CAudioListener {\n    pub position: CPosition3D,\n    pub velocity: CPosition3D,\n    pub forward: CPosition3D,\n    pub up: CPosition3D,\n    pub volume: c_float,\n}\n\n/// C-compatible audio source structure\n#[repr(C)]\n#[derive(Debug, Clone, Copy)]\npub struct CAudioSource {\n    pub position: CPosition3D,\n    pub velocity: CPosition3D,\n    pub volume: c_float,\n    pub pitch: c_float,\n    pub looping: c_int,\n    pub priority: c_int,\n    pub max_distance: c_float,\n    pub min_distance: c_float,\n}\n\n/// C-compatible device capabilities structure\n#[repr(C)]\npub struct CDeviceCapabilities {\n    pub hardware_mixing: c_int,\n    pub hardware_3d: c_int,\n    pub max_channels: c_uint,\n    pub min_buffer_size: c_uint,\n    pub max_buffer_size: c_uint,\n    pub latency_ms: c_float,\n    pub supported_sample_rates: *const c_uint,\n    pub sample_rate_count: c_uint,\n}\n\n/// Global audio device instance\nstatic GLOBAL_AUDIO_DEVICE: OnceLock<Arc<Mutex<Option<MilesAudioDevice>>>> = OnceLock::new();\n\n/// Global device manager instance\nstatic GLOBAL_DEVICE_MANAGER: OnceLock<Arc<Mutex<Option<DeviceManager>>>> = OnceLock::new();\n\n/// Global Tokio runtime for async operations\nstatic GLOBAL_RUNTIME: OnceLock<Arc<Runtime>> = OnceLock::new();\n\n/// Initialize the global runtime and components\nfn ensure_runtime() -> &'static Arc<Runtime> {\n    GLOBAL_RUNTIME.get_or_init(|| {\n        Arc::new(\n            tokio::runtime::Builder::new_multi_thread()\n                .enable_all()\n                .thread_name(\"audio-runtime\")\n                .build()\n                .expect(\"Failed to create Tokio runtime\")\n        )\n    })\n}\n\n/// Get or initialize the global audio device\nfn get_global_audio_device() -> &'static Arc<Mutex<Option<MilesAudioDevice>>> {\n    GLOBAL_AUDIO_DEVICE.get_or_init(|| Arc::new(Mutex::new(None)))\n}\n\n/// Get or initialize the global device manager\nfn get_global_device_manager() -> &'static Arc<Mutex<Option<DeviceManager>>> {\n    GLOBAL_DEVICE_MANAGER.get_or_init(|| Arc::new(Mutex::new(None)))\n}\n\n/// Convert Rust result to C result code\nfn rust_result_to_c(result: RustResult<()>) -> CResult {\n    match result {\n        Ok(()) => CResult::Success,\n        Err(AudioDeviceError::InitializationFailed(_)) => CResult::InitFailed,\n        Err(AudioDeviceError::DeviceNotFound(_)) => CResult::DeviceNotFound,\n        Err(AudioDeviceError::DeviceBusy(_)) => CResult::DeviceBusy,\n        Err(AudioDeviceError::FormatNotSupported(_)) => CResult::FormatNotSupported,\n        Err(AudioDeviceError::HardwareAccelNotAvailable(_)) => CResult::HardwareError,\n        Err(AudioDeviceError::IoError(_)) => CResult::Failure,\n        Err(_) => CResult::Failure,\n    }\n}\n\n/// Convert C audio format to Rust audio format\nfn c_to_rust_format(c_format: CAudioFormat) -> AudioFormat {\n    AudioFormat {\n        sample_rate: c_format.sample_rate,\n        channels: c_format.channels as u16,\n        bits_per_sample: c_format.bits_per_sample as u16,\n        format_type: match c_format.format_type {\n            0 => AudioFormatType::PcmInt,\n            1 => AudioFormatType::PcmFloat,\n            _ => AudioFormatType::PcmInt,\n        },\n    }\n}\n\n/// Convert C position to Rust position\nfn c_to_rust_position(c_pos: CPosition3D) -> Position3D {\n    Position3D::new(c_pos.x, c_pos.y, c_pos.z)\n}\n\n/// Convert C listener to Rust listener\nfn c_to_rust_listener(c_listener: CAudioListener) -> AudioListener {\n    AudioListener {\n        position: c_to_rust_position(c_listener.position),\n        velocity: c_to_rust_position(c_listener.velocity),\n        forward: c_to_rust_position(c_listener.forward),\n        up: c_to_rust_position(c_listener.up),\n        volume: c_listener.volume,\n    }\n}\n\n/// Convert C source to Rust source\nfn c_to_rust_source(c_source: CAudioSource) -> AudioSource {\n    AudioSource {\n        position: c_to_rust_position(c_source.position),\n        velocity: c_to_rust_position(c_source.velocity),\n        volume: c_source.volume,\n        pitch: c_source.pitch,\n        looping: c_source.looping != 0,\n        priority: match c_source.priority {\n            0 => Priority::Low,\n            50 => Priority::Normal,\n            80 => Priority::High,\n            100 => Priority::Critical,\n            _ => Priority::Normal,\n        },\n        max_distance: c_source.max_distance,\n        min_distance: c_source.min_distance,\n    }\n}\n\n// =============================================================================\n// C++ Compatible API Functions\n// These maintain exact signatures from the original MilesAudioDevice\n// =============================================================================\n\n/// Initialize the Miles Audio Device\n/// \n/// This is the main initialization function that must be called before any other audio functions.\n/// \n/// # Returns\n/// - `CResult::Success` if initialization succeeded\n/// - `CResult::InitFailed` if initialization failed\n/// - `CResult::DeviceNotFound` if no suitable audio device was found\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_Initialize() -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        // Initialize device manager first\n        let device_manager = match DeviceManager::new().await {\n            Ok(manager) => manager,\n            Err(e) => {\n                tracing::error!(\"Failed to initialize device manager: {:?}\", e);\n                return rust_result_to_c(Err(e));\n            }\n        };\n        \n        // Select default audio device\n        let selection = DeviceSelection::default();\n        let _device_id = match device_manager.select_device(selection).await {\n            Ok(id) => id,\n            Err(e) => {\n                tracing::error!(\"Failed to select audio device: {:?}\", e);\n                return rust_result_to_c(Err(e));\n            }\n        };\n        \n        // Get the initialized audio device\n        if let Some(audio_device) = device_manager.get_current_device().await {\n            // Store globally\n            *get_global_audio_device().lock().unwrap() = Some(audio_device);\n            *get_global_device_manager().lock().unwrap() = Some(device_manager);\n            \n            tracing::info!(\"MilesAudioDevice successfully initialized\");\n            CResult::Success\n        } else {\n            tracing::error!(\"Failed to get audio device after selection\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Initialize with specific configuration\n/// \n/// # Parameters\n/// - `preferred_driver`: Preferred audio driver name (can be null)\n/// - `speaker_config`: Preferred speaker configuration (can be null)\n/// - `enable_3d`: Enable 3D audio processing\n/// - `max_2d_samples`: Maximum number of 2D samples\n/// - `max_3d_samples`: Maximum number of 3D samples\n/// \n/// # Returns\n/// - `CResult::Success` if initialization succeeded\n/// - Error code if initialization failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_InitializeWithConfig(\n    preferred_driver: *const c_char,\n    speaker_config: *const c_char,\n    enable_3d: c_int,\n    max_2d_samples: c_uint,\n    max_3d_samples: c_uint,\n) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        // Convert C strings to Rust strings\n        let preferred_driver_str = if !preferred_driver.is_null() {\n            unsafe {\n                match CStr::from_ptr(preferred_driver).to_str() {\n                    Ok(s) => Some(s.to_string()),\n                    Err(_) => None,\n                }\n            }\n        } else {\n            None\n        };\n        \n        let speaker_config_str = if !speaker_config.is_null() {\n            unsafe {\n                match CStr::from_ptr(speaker_config).to_str() {\n                    Ok(s) => Some(s.to_string()),\n                    Err(_) => None,\n                }\n            }\n        } else {\n            None\n        };\n        \n        // Create audio configuration\n        let config = MilesAudioConfig {\n            preferred_driver: preferred_driver_str,\n            preferred_speaker_config: speaker_config_str,\n            enable_3d_audio: enable_3d != 0,\n            max_2d_samples: max_2d_samples as usize,\n            max_3d_samples: max_3d_samples as usize,\n            ..Default::default()\n        };\n        \n        // Initialize with custom config\n        match MilesAudioDevice::new_with_config(config).await {\n            Ok(mut device) => {\n                match device.init().await {\n                    Ok(()) => {\n                        *get_global_audio_device().lock().unwrap() = Some(device);\n                        tracing::info!(\"MilesAudioDevice initialized with custom configuration\");\n                        CResult::Success\n                    }\n                    Err(e) => {\n                        tracing::error!(\"Failed to initialize audio device: {:?}\", e);\n                        rust_result_to_c(Err(e))\n                    }\n                }\n            }\n            Err(e) => {\n                tracing::error!(\"Failed to create audio device: {:?}\", e);\n                rust_result_to_c(Err(e))\n            }\n        }\n    })\n}\n\n/// Create a sound buffer with specified size and format\n/// \n/// # Parameters\n/// - `size`: Size of the buffer in bytes\n/// - `format`: Audio format specification\n/// - `buffer_id`: Output parameter for the created buffer ID\n/// \n/// # Returns\n/// - `CResult::Success` if buffer was created successfully\n/// - Error code if buffer creation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_CreateSoundBuffer(\n    size: c_uint,\n    format: CAudioFormat,\n    buffer_id: *mut c_uint,\n) -> CResult {\n    if buffer_id.is_null() {\n        return CResult::InvalidParam;\n    }\n    \n    let rust_format = c_to_rust_format(format);\n    \n    // Create buffer using the sound buffer system\n    use super::SoundBuffer;\n    let buffer = SoundBuffer::new(rust_format, super::BufferFormat::Interleaved);\n    \n    // Allocate buffer data\n    let empty_data = vec![0u8; size as usize];\n    match buffer.load_from_bytes(&empty_data) {\n        Ok(()) => {\n            // For simplicity, use the buffer's UUID hash as the ID\n            let id = buffer.id.as_u128() as c_uint;\n            unsafe {\n                *buffer_id = id;\n            }\n            \n            tracing::debug!(\"Created sound buffer: ID={}, size={}\", id, size);\n            CResult::Success\n        }\n        Err(e) => {\n            tracing::error!(\"Failed to create sound buffer: {:?}\", e);\n            rust_result_to_c(Err(e))\n        }\n    }\n}\n\n/// Play a sound with specified parameters\n/// \n/// # Parameters\n/// - `file_path`: Path to the audio file to play\n/// - `volume`: Volume level (0.0 to 1.0)\n/// - `pan`: Pan position (-1.0 to 1.0, 0.0 is center)\n/// - `priority`: Sound priority level\n/// - `looping`: Whether the sound should loop\n/// - `handle`: Output parameter for the audio handle\n/// \n/// # Returns\n/// - `CResult::Success` if sound started playing\n/// - Error code if playback failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_PlaySound(\n    file_path: *const c_char,\n    volume: c_float,\n    pan: c_float,\n    priority: c_int,\n    looping: c_int,\n    handle: *mut c_uint,\n) -> CResult {\n    if file_path.is_null() || handle.is_null() {\n        return CResult::InvalidParam;\n    }\n    \n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let path_str = unsafe {\n            match CStr::from_ptr(file_path).to_str() {\n                Ok(s) => s,\n                Err(_) => return CResult::InvalidParam,\n            }\n        };\n        \n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let mut source_config = AudioSource::default();\n            source_config.volume = volume.clamp(0.0, 1.0);\n            source_config.looping = looping != 0;\n            source_config.priority = match priority {\n                0 => Priority::Low,\n                50 => Priority::Normal,\n                80 => Priority::High,\n                100 => Priority::Critical,\n                _ => Priority::Normal,\n            };\n            \n            // Apply pan by adjusting position slightly\n            source_config.position.x = pan * 0.1; // Small positional adjustment for pan effect\n            \n            match device.play_audio(path_str, source_config).await {\n                Ok(audio_handle) => {\n                    unsafe {\n                        *handle = audio_handle.0 as c_uint;\n                    }\n                    tracing::debug!(\"Started playing sound: {} (handle={})\", path_str, audio_handle.0);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to play sound {}: {:?}\", path_str, e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Play a 3D positioned sound\n/// \n/// # Parameters\n/// - `file_path`: Path to the audio file to play\n/// - `source`: 3D audio source configuration\n/// - `handle`: Output parameter for the audio handle\n/// \n/// # Returns\n/// - `CResult::Success` if sound started playing\n/// - Error code if playback failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_PlaySound3D(\n    file_path: *const c_char,\n    source: CAudioSource,\n    handle: *mut c_uint,\n) -> CResult {\n    if file_path.is_null() || handle.is_null() {\n        return CResult::InvalidParam;\n    }\n    \n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let path_str = unsafe {\n            match CStr::from_ptr(file_path).to_str() {\n                Ok(s) => s,\n                Err(_) => return CResult::InvalidParam,\n            }\n        };\n        \n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let rust_source = c_to_rust_source(source);\n            \n            match device.play_audio(path_str, rust_source).await {\n                Ok(audio_handle) => {\n                    unsafe {\n                        *handle = audio_handle.0 as c_uint;\n                    }\n                    tracing::debug!(\"Started playing 3D sound: {} (handle={})\", path_str, audio_handle.0);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to play 3D sound {}: {:?}\", path_str, e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Stop a playing sound\n/// \n/// # Parameters\n/// - `handle`: Handle of the sound to stop\n/// \n/// # Returns\n/// - `CResult::Success` if sound was stopped\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_StopSound(handle: c_uint) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let audio_handle = AudioHandle(handle as u64);\n            \n            match device.stop_audio(audio_handle).await {\n                Ok(()) => {\n                    tracing::debug!(\"Stopped sound: handle={}\", handle);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to stop sound {}: {:?}\", handle, e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Pause a playing sound\n/// \n/// # Parameters\n/// - `handle`: Handle of the sound to pause\n/// \n/// # Returns\n/// - `CResult::Success` if sound was paused\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_PauseSound(handle: c_uint) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let audio_handle = AudioHandle(handle as u64);\n            \n            match device.pause_audio(audio_handle).await {\n                Ok(()) => {\n                    tracing::debug!(\"Paused sound: handle={}\", handle);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to pause sound {}: {:?}\", handle, e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Resume a paused sound\n/// \n/// # Parameters\n/// - `handle`: Handle of the sound to resume\n/// \n/// # Returns\n/// - `CResult::Success` if sound was resumed\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_ResumeSound(handle: c_uint) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let audio_handle = AudioHandle(handle as u64);\n            \n            match device.resume_audio(audio_handle).await {\n                Ok(()) => {\n                    tracing::debug!(\"Resumed sound: handle={}\", handle);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to resume sound {}: {:?}\", handle, e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Set the 3D audio listener position and orientation\n/// \n/// # Parameters\n/// - `listener`: Listener configuration\n/// \n/// # Returns\n/// - `CResult::Success` if listener was updated\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_SetListenerPosition(listener: CAudioListener) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let rust_listener = c_to_rust_listener(listener);\n            \n            match device.update_listener(rust_listener).await {\n                Ok(()) => {\n                    tracing::debug!(\"Updated listener position: {:?}\", listener.position);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to update listener: {:?}\", e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Check if a sound is currently playing\n/// \n/// # Parameters\n/// - `handle`: Handle of the sound to check\n/// \n/// # Returns\n/// - 1 if sound is playing\n/// - 0 if sound is not playing or handle is invalid\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_IsSoundPlaying(handle: c_uint) -> c_int {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let audio_handle = AudioHandle(handle as u64);\n            \n            match device.is_playing(audio_handle).await {\n                Ok(is_playing) => {\n                    if is_playing { 1 } else { 0 }\n                }\n                Err(_) => 0,\n            }\n        } else {\n            0\n        }\n    })\n}\n\n/// Get device capabilities\n/// \n/// # Parameters\n/// - `capabilities`: Output parameter for device capabilities\n/// \n/// # Returns\n/// - `CResult::Success` if capabilities were retrieved\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_GetCapabilities(capabilities: *mut CDeviceCapabilities) -> CResult {\n    if capabilities.is_null() {\n        return CResult::InvalidParam;\n    }\n    \n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let rust_capabilities = device.get_capabilities().await;\n            \n            unsafe {\n                (*capabilities).hardware_mixing = if rust_capabilities.hardware_mixing { 1 } else { 0 };\n                (*capabilities).hardware_3d = if rust_capabilities.hardware_3d { 1 } else { 0 };\n                (*capabilities).max_channels = rust_capabilities.max_channels as c_uint;\n                (*capabilities).min_buffer_size = rust_capabilities.min_buffer_size;\n                (*capabilities).max_buffer_size = rust_capabilities.max_buffer_size;\n                (*capabilities).latency_ms = rust_capabilities.latency_ms;\n                \n                // Note: For simplicity, not setting sample rates array in this example\n                // In production, you would allocate and fill the array\n                (*capabilities).supported_sample_rates = ptr::null();\n                (*capabilities).sample_rate_count = 0;\n            }\n            \n            CResult::Success\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Set master volume\n/// \n/// # Parameters\n/// - `volume`: Master volume (0.0 to 1.0)\n/// \n/// # Returns\n/// - `CResult::Success` if volume was set\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_SetMasterVolume(volume: c_float) -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            // Update listener with new volume\n            let mut listener = AudioListener::default();\n            listener.volume = volume.clamp(0.0, 1.0);\n            \n            match device.update_listener(listener).await {\n                Ok(()) => {\n                    tracing::debug!(\"Set master volume: {}\", volume);\n                    CResult::Success\n                }\n                Err(e) => {\n                    tracing::error!(\"Failed to set master volume: {:?}\", e);\n                    rust_result_to_c(Err(e))\n                }\n            }\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n/// Shutdown the audio device\n/// \n/// This function must be called to properly cleanup the audio system.\n/// \n/// # Returns\n/// - `CResult::Success` if shutdown was successful\n/// - Error code if shutdown failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_Shutdown() -> CResult {\n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        // Shutdown device manager first\n        {\n            let mut manager_guard = get_global_device_manager().lock().unwrap();\n            if let Some(manager) = manager_guard.take() {\n                if let Err(e) = manager.shutdown().await {\n                    tracing::error!(\"Failed to shutdown device manager: {:?}\", e);\n                    return rust_result_to_c(Err(e));\n                }\n            }\n        }\n        \n        // Shutdown audio device\n        {\n            let mut device_guard = get_global_audio_device().lock().unwrap();\n            if let Some(device) = device_guard.take() {\n                if let Err(e) = device.shutdown().await {\n                    tracing::error!(\"Failed to shutdown audio device: {:?}\", e);\n                    return rust_result_to_c(Err(e));\n                }\n            }\n        }\n        \n        tracing::info!(\"MilesAudioDevice shutdown completed\");\n        CResult::Success\n    })\n}\n\n// =============================================================================\n// Additional Utility Functions\n// =============================================================================\n\n/// Get the version string of the audio system\n/// \n/// # Returns\n/// - Pointer to version string (must not be freed by caller)\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_GetVersion() -> *const c_char {\n    static VERSION: &str = \"GameEngineDevice Audio v1.0.0\\0\";\n    VERSION.as_ptr() as *const c_char\n}\n\n/// Get the last error message\n/// \n/// # Returns\n/// - Pointer to error string (must not be freed by caller)\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_GetLastError() -> *const c_char {\n    static ERROR_MSG: &str = \"No error\\0\";\n    ERROR_MSG.as_ptr() as *const c_char\n}\n\n/// Check if the audio system is initialized\n/// \n/// # Returns\n/// - 1 if initialized\n/// - 0 if not initialized\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_IsInitialized() -> c_int {\n    let device_guard = get_global_audio_device().lock().unwrap();\n    if device_guard.is_some() { 1 } else { 0 }\n}\n\n/// Get audio statistics\n/// \n/// # Parameters\n/// - `active_sounds`: Output parameter for number of active sounds\n/// - `cpu_usage`: Output parameter for CPU usage percentage\n/// - `memory_usage`: Output parameter for memory usage in bytes\n/// \n/// # Returns\n/// - `CResult::Success` if statistics were retrieved\n/// - Error code if operation failed\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_GetStatistics(\n    active_sounds: *mut c_uint,\n    cpu_usage: *mut c_float,\n    memory_usage: *mut c_uint,\n) -> CResult {\n    if active_sounds.is_null() || cpu_usage.is_null() || memory_usage.is_null() {\n        return CResult::InvalidParam;\n    }\n    \n    let runtime = ensure_runtime();\n    \n    runtime.block_on(async {\n        let device_guard = get_global_audio_device().lock().unwrap();\n        if let Some(ref device) = *device_guard {\n            let stats = device.get_statistics().await;\n            \n            unsafe {\n                *active_sounds = stats.active_channels as c_uint;\n                *cpu_usage = stats.cpu_usage;\n                *memory_usage = (stats.memory_usage / 1024) as c_uint; // Convert to KB\n            }\n            \n            CResult::Success\n        } else {\n            tracing::error!(\"Audio device not initialized\");\n            CResult::InitFailed\n        }\n    })\n}\n\n// =============================================================================\n// C++ Class-like Interface (Optional)\n// =============================================================================\n\n/// Opaque handle for C++ class-like interface\n#[repr(C)]\npub struct MilesAudioDeviceHandle {\n    _private: [u8; 0],\n}\n\n/// Create a new MilesAudioDevice instance (C++ class-like interface)\n/// \n/// # Returns\n/// - Pointer to device handle, or null on failure\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_Create() -> *mut MilesAudioDeviceHandle {\n    let runtime = ensure_runtime();\n    \n    match runtime.block_on(async {\n        MilesAudioDevice::new().await\n    }) {\n        Ok(device) => {\n            let boxed_device = Box::new(device);\n            Box::into_raw(boxed_device) as *mut MilesAudioDeviceHandle\n        }\n        Err(_) => ptr::null_mut(),\n    }\n}\n\n/// Destroy a MilesAudioDevice instance (C++ class-like interface)\n/// \n/// # Parameters\n/// - `handle`: Handle to the device instance\n#[no_mangle]\npub extern \"C\" fn MilesAudioDevice_Destroy(handle: *mut MilesAudioDeviceHandle) {\n    if !handle.is_null() {\n        let runtime = ensure_runtime();\n        unsafe {\n            let device = Box::from_raw(handle as *mut MilesAudioDevice);\n            let _ = runtime.block_on(async {\n                device.shutdown().await\n            });\n        }\n    }\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n    use std::ffi::CString;\n    \n    #[test]\n    fn test_c_format_conversion() {\n        let c_format = CAudioFormat {\n            sample_rate: 44100,\n            channels: 2,\n            bits_per_sample: 16,\n            format_type: 0,\n        };\n        \n        let rust_format = c_to_rust_format(c_format);\n        assert_eq!(rust_format.sample_rate, 44100);\n        assert_eq!(rust_format.channels, 2);\n        assert_eq!(rust_format.bits_per_sample, 16);\n    }\n    \n    #[test]\n    fn test_position_conversion() {\n        let c_pos = CPosition3D {\n            x: 1.0,\n            y: 2.0,\n            z: 3.0,\n        };\n        \n        let rust_pos = c_to_rust_position(c_pos);\n        assert_eq!(rust_pos.x, 1.0);\n        assert_eq!(rust_pos.y, 2.0);\n        assert_eq!(rust_pos.z, 3.0);\n    }\n    \n    #[test]\n    fn test_version_string() {\n        let version = MilesAudioDevice_GetVersion();\n        assert!(!version.is_null());\n        \n        let version_str = unsafe {\n            CStr::from_ptr(version).to_str().unwrap()\n        };\n        \n        assert!(version_str.contains(\"GameEngineDevice\"));\n    }\n}"